// src/utils/video.js
var RawVideoFrame = class {
  /**
   * @param {RawImage} image
   * @param {number} timestamp
   */
  constructor(image, timestamp) {
    this.image = image;
    this.timestamp = timestamp;
  }
};
var RawVideo = class {
  /**
   * @param {RawVideoFrame[]|RawImage[]} frames
   * @param {number} duration
   */
  constructor(frames, duration) {
    if (frames.length > 0 && frames[0] instanceof RawImage) {
      frames = frames.map((image, i) => new RawVideoFrame(image, (i + 1) / (frames.length + 1) * duration));
    }
    this.frames = /** @type {RawVideoFrame[]} */
    frames;
    this.duration = duration;
  }
  get width() {
    return this.frames[0].image.width;
  }
  get height() {
    return this.frames[0].image.height;
  }
  get fps() {
    return this.frames.length / this.duration;
  }
};
async function load_video(src, { num_frames = null, fps = null } = {}) {
  if (!apis.IS_BROWSER_ENV) {
    throw new Error("`load_video` is currently only supported in browser environments.");
  }
  if (num_frames == null && fps == null) {
    throw new Error("Either num_frames or fps must be provided.");
  }
  const frames = [];
  const video = document.createElement("video");
  video.crossOrigin = "anonymous";
  video.muted = true;
  if (typeof src === "string") {
    video.src = src;
  } else if (src instanceof Blob) {
    video.src = URL.createObjectURL(src);
  } else if (src instanceof HTMLVideoElement) {
    video.src = src.src;
  } else {
    throw new Error("Invalid URL or video element provided.");
  }
  await new Promise((resolve) => video.onloadedmetadata = resolve);
  if (video.seekable.start(0) === video.seekable.end(0)) {
    const response = await env.fetch(video.src);
    const blob = await response.blob();
    video.src = URL.createObjectURL(blob);
    await new Promise((resolve) => video.onloadedmetadata = resolve);
  }
  const duration = video.duration;
  let count2, step;
  if (num_frames != null) {
    count2 = num_frames;
    step = num_frames === 1 ? 0 : duration / (num_frames - 1);
  } else {
    step = 1 / fps;
    count2 = Math.floor(duration / step);
  }
  let sampleTimes = [];
  for (let i = 0; i < count2; ++i) {
    sampleTimes.push(num_frames === 1 ? duration / 2 : i * step);
  }
  const canvas = document.createElement("canvas");
  canvas.width = video.videoWidth;
  canvas.height = video.videoHeight;
  const ctx = canvas.getContext("2d", { willReadFrequently: true });
  for (const t of sampleTimes) {
    video.currentTime = t;
    await new Promise((resolve) => {
      video.onseeked = resolve;
    });
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const frameData = new RawImage(imageData.data, canvas.width, canvas.height, 4);
    const frame = new RawVideoFrame(frameData, t);
    frames.push(frame);
  }
  video.remove();
  return new RawVideo(frames, duration);
}

// src/utils/model_registry/is_cached.js
async function check_files_cache(modelId, files, options = {}) {
  const cache2 = await getCache(options?.cache_dir);
  if (!cache2) {
    const fileStatuses2 = files.map((filename) => ({ file: filename, cached: false }));
    return { allCached: false, files: fileStatuses2 };
  }
  const fileStatuses = await Promise.all(
    files.map(async (filename) => {
      const { localPath, proposedCacheKey } = buildResourcePaths(modelId, filename, options, cache2);
      const cached = await checkCachedResource(cache2, localPath, proposedCacheKey);
      return { file: filename, cached: !!cached };
    })
  );
  return { allCached: fileStatuses.every((f) => f.cached), files: fileStatuses };
}
async function is_file_cached(modelId, filename, options = {}) {
  const cache2 = await getCache(options?.cache_dir);
  if (!cache2) return false;
  const { localPath, proposedCacheKey } = buildResourcePaths(modelId, filename, options, cache2);
  return !!await checkCachedResource(cache2, localPath, proposedCacheKey);
}
async function is_cached(modelId, options = {}) {
  if (!modelId) {
    throw new Error("modelId is required");
  }
  if (!await is_file_cached(modelId, "config.json", options)) {
    return false;
  }
  const files = await get_files(modelId, options);
  const result = await check_files_cache(modelId, files, options);
  return result.allCached;
}
async function is_cached_files(modelId, options = {}) {
  if (!modelId) {
    throw new Error("modelId is required");
  }
  const files = await get_files(modelId, options);
  return await check_files_cache(modelId, files, options);
}
async function is_pipeline_cached(task, modelId, options = {}) {
  if (!task) {
    throw new Error("task is required");
  }
  if (!modelId) {
    throw new Error("modelId is required");
  }
  if (!await is_file_cached(modelId, "config.json", options)) {
    return false;
  }
  const files = await get_pipeline_files(task, modelId, options);
  const result = await check_files_cache(modelId, files, options);
  return result.allCached;
}
async function is_pipeline_cached_files(task, modelId, options = {}) {
  if (!task) {
    throw new Error("task is required");
  }
  if (!modelId) {
    throw new Error("modelId is required");
  }
  const files = await get_pipeline_files(task, modelId, options);
  return await check_files_cache(modelId, files, options);
}

// src/utils/model_registry/clear_cache.js
async function clear_files_from_cache(modelId, files, options = {}) {
  const cache2 = await getCache(options?.cache_dir);
  if (!cache2) {
    return {
      filesDeleted: 0,
      filesCached: 0,
      files: files.map((filename) => ({ file: filename, deleted: false, wasCached: false }))
    };
  }
  if (!cache2.delete) {
    throw new Error("Cache does not support delete operation");
  }
  const results = await Promise.all(
    files.map(async (filename) => {
      const { localPath, proposedCacheKey } = buildResourcePaths(modelId, filename, options, cache2);
      const cached = await checkCachedResource(cache2, localPath, proposedCacheKey);
      const wasCached = !!cached;
      let deleted = false;
      if (wasCached) {
        const deletedWithProposed = await cache2.delete(proposedCacheKey);
        const deletedWithLocal = !deletedWithProposed && proposedCacheKey !== localPath ? await cache2.delete(localPath) : false;
        deleted = deletedWithProposed || deletedWithLocal;
      }
      return { file: filename, deleted, wasCached };
    })
  );
  return {
    filesDeleted: results.filter((r) => r.deleted).length,
    filesCached: results.filter((r) => r.wasCached).length,
    files: results
  };
}
async function clear_cache(modelId, options = {}) {
  if (!modelId) {
    throw new Error("modelId is required");
  }
  const files = await get_files(modelId, options);
  return await clear_files_from_cache(modelId, files, options);
}
async function clear_pipeline_cache(task, modelId, options = {}) {
  if (!task) {
    throw new Error("task is required");
  }
  if (!modelId) {
    throw new Error("modelId is required");
  }
  const files = await get_pipeline_files(task, modelId, options);
  return await clear_files_from_cache(modelId, files, options);
}

// src/utils/model_registry/get_available_dtypes.js
var CONCRETE_DTYPES = Object.keys(DEFAULT_DTYPE_SUFFIX_MAPPING);
async function get_available_dtypes(modelId, { config = null, model_file_name = null, revision = "main", cache_dir = null, local_files_only = false } = {}) {
  config = await get_config(modelId, { config, cache_dir, local_files_only, revision });
  const subfolder = "onnx";
  const modelType = resolve_model_type(config);
  const { sessions } = getSessionsConfig(modelType, config, { model_file_name });
  const baseNames = Object.values(sessions);
  const metadataOptions = { revision, cache_dir, local_files_only };
  const probeResults = await Promise.all(
    CONCRETE_DTYPES.map(async (dtype) => {
      const suffix = DEFAULT_DTYPE_SUFFIX_MAPPING[dtype] ?? "";
      const allExist = await Promise.all(
        baseNames.map(async (baseName) => {
          const filename = `${subfolder}/${baseName}${suffix}.onnx`;
          const metadata = await get_file_metadata(modelId, filename, metadataOptions);
          return metadata.exists;
        })
      );
      return { dtype, available: allExist.every(Boolean) };
    })
  );
  return probeResults.filter((r) => r.available).map((r) => r.dtype);
}

